"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { 
  Share2, 
  Volume2, 
  RefreshCw, 
  Quote, 
  Check,
  Sparkles
} from "lucide-react";
import { jokesData, type Language, type Joke } from "@/data/jokes";
import { cn } from "@/lib/utils";

const HasmukhLogo = ({ className = "w-10 h-10" }: { className?: string }) => (
  <svg 
    viewBox="0 0 100 100" 
    className={className}
    fill="none" 
    xmlns="http://www.w3.org/2000/svg"
  >
    <defs>
      <linearGradient id="logoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#FB923C" />
        <stop offset="100%" stopColor="#F43F5E" />
      </linearGradient>
    </defs>
    <path 
      d="M20 25C20 19.4772 24.4772 15 30 15H70C75.5228 15 80 19.4772 80 25V60C80 65.5228 75.5228 70 70 70H45L25 85V70H20C14.4772 70 10 65.5228 10 60V25C10 19.4772 14.4772 15 20 15Z" 
      stroke="url(#logoGradient)" 
      strokeWidth="6" 
      strokeLinecap="round" 
      strokeLinejoin="round"
    />
    <path 
      d="M35 45C35 45 42.5 55 50 55C57.5 55 65 45 65 45" 
      stroke="url(#logoGradient)" 
      strokeWidth="6" 
      strokeLinecap="round"
    />
  </svg>
);

export default function Home() {
  const [lang, setLang] = useState<Language>("en");
  const [currentJoke, setCurrentJoke] = useState<Joke>(jokesData.en[0]);
  const [isLoading, setIsLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    getRandomJoke(lang);
  }, [lang]);

  const getRandomJoke = async (targetLang: Language) => {
    setIsLoading(true);
    let apiSuccess = false;

    // 1. API Integration
    try {
      const response = await fetch(`https://v2.jokeapi.dev/joke/Any?type=single&safe-mode&lang=${targetLang}`);
      const data = await response.json();

      if (!response.ok || data.error || !data.joke) {
        throw new Error("Language not supported by external API or network error");
      }

      setCurrentJoke({ id: data.id, text: data.joke });
      apiSuccess = true;
    } catch (error) {
      console.warn("External API unavailable or language unsupported. Falling back to local data.");
    }

    // 2. Fallback Logic
    if (!apiSuccess) {
      const languageJokes = jokesData[targetLang];
      if (languageJokes && languageJokes.length > 0) {
        let newJoke: Joke;
        do {
          newJoke = languageJokes[Math.floor(Math.random() * languageJokes.length)];
        } while (languageJokes.length > 1 && newJoke.id === currentJoke.id && lang === targetLang);
        setCurrentJoke(newJoke);
      } else {
        setCurrentJoke({ id: 0, text: "Error: No jokes found for this language." });
      }
    }

    setIsLoading(false);
  };

  const handleShare = async () => {
    const text = `${currentJoke.text}\n\nGenerated by Hasmukh App`;
    if (navigator.share) {
      try {
        await navigator.share({
          title: "Hasmukh - Daily Dose of Laughter",
          text: text,
          url: window.location.href,
        });
      } catch (err) {
        console.error("Error sharing:", err);
      }
    } else {
      try {
        await navigator.clipboard.writeText(text);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      } catch (err) {
        console.error("Error copying:", err);
      }
    }
  };

  const speakJoke = () => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(currentJoke.text);
    switch (lang) {
      case "hi": utterance.lang = "hi-IN"; break;
      case "mr": utterance.lang = "mr-IN"; break;
      case "ta": utterance.lang = "ta-IN"; break;
      case "te": utterance.lang = "te-IN"; break;
      case "ml": utterance.lang = "ml-IN"; break;
      default: utterance.lang = "en-US";
    }
    window.speechSynthesis.speak(utterance);
  };

  const languages: { code: Language; label: string }[] = [
    { code: "en", label: "English" },
    { code: "hi", label: "हिंदी" },
    { code: "mr", label: "मराठी" },
    { code: "ta", label: "தமிழ்" },
    { code: "te", label: "తెలుగు" },
    { code: "ml", label: "മലയാളം" },
  ];

  return (
    <main className="min-h-screen flex flex-col justify-between items-center saas-bg text-white p-6 md:p-12 overflow-hidden relative">
      
      {/* 1. Atmospheric Depth (Background Blobs) */}
      <div className="fixed inset-0 pointer-events-none z-[-1]">
        <div className="bg-indigo-500/10 blur-[150px] w-96 h-96 absolute -top-20 -right-20 rounded-full" />
        <div className="bg-orange-500/10 blur-[150px] w-96 h-96 absolute -bottom-20 -left-20 rounded-full" />
      </div>

      {/* 3. Branding & Navigation (Horizontal Layout) */}
      <header className="w-full max-w-7xl flex justify-between items-center z-10">
        <motion.div 
          initial={{ x: -20, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          className="flex items-center gap-4 group cursor-default"
        >
          <div className="relative">
            <HasmukhLogo className="w-12 h-12 transition-transform duration-500 group-hover:rotate-12" />
            <Sparkles className="absolute -top-1 -right-1 w-4 h-4 text-orange-400 opacity-0 group-hover:opacity-100 transition-opacity" />
          </div>
          <h1 className="text-saas-gradient font-black text-2xl tracking-widest drop-shadow-sm">
            HASMUKH
          </h1>
        </motion.div>

        <nav className="flex gap-2">
          {languages.map((l) => (
            <button
              key={l.code}
              onClick={() => setLang(l.code)}
              className={cn(
                "rounded-full px-5 py-2 text-sm font-bold transition-all shadow-lg",
                lang === l.code 
                  ? "bg-white text-black scale-105" 
                  : "bg-white/5 text-slate-400 hover:text-white"
              )}
            >
              {l.label}
            </button>
          ))}
        </nav>
      </header>

      {/* 2. Premium 'Glass' Joke Card */}
      <div className="flex-1 w-full max-w-5xl flex items-center justify-center py-12 z-10">
        <motion.div 
          initial={{ opacity: 0, scale: 0.98 }}
          animate={{ opacity: 1, scale: 1 }}
          className="w-full glass-card-premium backdrop-blur-[40px] rounded-[3rem] p-16 border border-white/10 relative shadow-[0_30px_100px_-15px_rgba(0,0,0,0.8)] flex items-center justify-center overflow-hidden min-h-[400px]"
        >
          {/* Quotes at 10% opacity */}
          <div className="absolute top-12 left-12 opacity-10">
            <Quote size={48} className="text-white fill-white drop-shadow-2xl" />
          </div>
          <div className="absolute bottom-12 right-12 opacity-10 rotate-180">
            <Quote size={48} className="text-white fill-white drop-shadow-2xl" />
          </div>

          <div className="z-10 w-full px-4">
            <AnimatePresence mode="wait">
              <motion.div
                key={currentJoke.id + lang}
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -30 }}
                transition={{ duration: 0.5, ease: "easeOut" }}
                className="flex items-center justify-center"
              >
                <p className={cn(
                  "text-white text-center drop-shadow-2xl",
                  lang === 'en' 
                    ? "font-[var(--font-poppins)] text-4xl font-medium tracking-tight" 
                    : "font-[var(--font-noto-sans-devanagari)] text-5xl font-semibold leading-relaxed"
                )}>
                  {currentJoke.text}
                </p>
              </motion.div>
            </AnimatePresence>
          </div>
        </motion.div>
      </div>

      {/* 4. The 'Action Dock' (Bottom Navigation) */}
      <footer className="w-full flex flex-col items-center gap-10 pb-6 z-10">
        <div className="flex items-center gap-8 p-3 bg-white/5 backdrop-blur-[40px] rounded-full border border-white/5 shadow-2xl">
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={() => getRandomJoke(lang)}
            disabled={isLoading}
            className="bg-saas-gradient btn-glow-saas px-12 py-4 rounded-full font-bold text-white flex items-center gap-3 disabled:opacity-50 transition-all duration-300"
          >
            <RefreshCw size={24} className={cn("transition-transform duration-500", isLoading && "animate-spin")} />
            <span className="text-lg tracking-wide">Next Laugh</span>
          </motion.button>

          <div className="flex items-center gap-4 pr-3">
            <motion.button
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              onClick={speakJoke}
              className="w-14 h-14 flex items-center justify-center rounded-full border border-white/20 text-white/70 hover:bg-white/10 hover:text-white transition-colors shadow-lg"
              aria-label="Speak joke"
            >
              <Volume2 size={24} />
            </motion.button>

            <motion.button
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              onClick={handleShare}
              className="w-14 h-14 flex items-center justify-center rounded-full border border-white/20 text-white/70 hover:bg-white/10 hover:text-white transition-colors relative shadow-lg"
              aria-label="Share joke"
            >
              {copied ? <Check size={24} className="text-green-500" /> : <Share2 size={24} />}
              <AnimatePresence>
                {copied && (
                  <motion.span 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0 }}
                    className="absolute -top-14 left-1/2 -translate-x-1/2 bg-white text-black text-xs font-black py-2 px-4 rounded-xl shadow-2xl"
                  >
                    COPIED!
                  </motion.span>
                )}
              </AnimatePresence>
            </motion.button>
          </div>
        </div>

        <div className="flex flex-col items-center gap-2">
          <p className="text-[11px] uppercase tracking-[0.4em] font-bold text-slate-500 opacity-60 drop-shadow-sm">
            © {new Date().getFullYear()} HASMUKH • PURE LAUGHTER
          </p>
          <div className="h-1 w-12 bg-saas-gradient rounded-full opacity-40 blur-[1px]" />
        </div>
      </footer>
    </main>
  );
}
